#include <bits/stdc++.h>
using namespace std;
#define int unsigned long long
void slove() {
	int n;
	cin>>n;
	int stk[n+5],size=0;
	while(n--) {
		string x;
		cin>>x;
		if(x=="push") {
			int s;
			cin>>s;
			stk[size++]=s;
		} else if(x=="pop") {
			if(size>0) {
				size--;
			} else {
				cout<<"Empty";
				cout<<"\n";
			}
		} else if(x=="query") {
			if(size) {
				cout<<stk[size-1];
			} else {
				cout<<"Anguei!";
			}
			cout<<"\n";
		} else {
			cout<<size;
			cout<<"\n";
		}
	}
}
int t;
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>t;
	while(t--) {
		slove();
	}
	return 0;
}
